package main

import (
	"fmt"
	"mime"
	"net/http"
	"os"
	"path/filepath"
	"strings"
)

const uploadsDir = "./uploads"

func fileHandler(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodGet {
		http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
		return
	}

	filename := r.URL.Query().Get("filename")
	if filename == "" {
		http.Error(w, "Missing filename parameter", http.StatusBadRequest)
		return
	}

	// Reject any filename that is an absolute path
	if filepath.IsAbs(filename) {
		http.Error(w, "Invalid filename", http.StatusBadRequest)
		return
	}

	// Reject filenames containing path traversal segments
	// Check each component of the path
	for _, part := range strings.Split(filepath.ToSlash(filename), "/") {
		if part == ".." || part == "." {
			http.Error(w, "Invalid filename", http.StatusBadRequest)
			return
		}
	}

	// Reject filenames with null bytes
	if strings.ContainsRune(filename, 0) {
		http.Error(w, "Invalid filename", http.StatusBadRequest)
		return
	}

	// Resolve the canonical absolute path of the uploads directory
	absUploadsDir, err := filepath.Abs(uploadsDir)
	if err != nil {
		http.Error(w, "Internal server error", http.StatusInternalServerError)
		return
	}

	canonicalUploadsDir, err := filepath.EvalSymlinks(absUploadsDir)
	if err != nil {
		http.Error(w, "Internal server error", http.StatusInternalServerError)
		return
	}

	// Join the base directory with the requested filename
	requestedPath := filepath.Join(canonicalUploadsDir, filename)

	// Resolve the canonical absolute path of the requested file
	// This resolves any symlinks that might point outside the uploads directory
	canonicalRequestedPath, err := filepath.EvalSymlinks(requestedPath)
	if err != nil {
		if os.IsNotExist(err) {
			http.Error(w, "File not found", http.StatusNotFound)
			return
		}
		http.Error(w, "Internal server error", http.StatusInternalServerError)
		return
	}

	// Ensure the resolved path is within the uploads directory
	// Add a trailing separator to prevent prefix matching attacks
	// (e.g., /uploads-evil matching /uploads)
	if !strings.HasPrefix(canonicalRequestedPath, canonicalUploadsDir+string(os.PathSeparator)) &&
		canonicalRequestedPath != canonicalUploadsDir {
		http.Error(w, "Access denied", http.StatusForbidden)
		return
	}

	// Verify the path points to a regular file (not a directory or special file)
	fileInfo, err := os.Stat(canonicalRequestedPath)
	if err != nil {
		if os.IsNotExist(err) {
			http.Error(w, "File not found", http.StatusNotFound)
			return
		}
		http.Error(w, "Internal server error", http.StatusInternalServerError)
		return
	}

	if fileInfo.IsDir() {
		http.Error(w, "Cannot serve directories", http.StatusBadRequest)
		return
	}

	if !fileInfo.Mode().IsRegular() {
		http.Error(w, "Invalid file type", http.StatusBadRequest)
		return
	}

	// Open and read the file
	file, err := os.Open(canonicalRequestedPath)
	if err != nil {
		http.Error(w, "Internal server error", http.StatusInternalServerError)
		return
	}
	defer file.Close()

	// Determine the content type based on file extension
	ext := filepath.Ext(canonicalRequestedPath)
	contentType := mime.TypeByExtension(ext)
	if contentType == "" {
		// Fall back to reading the first 512 bytes for detection
		buffer := make([]byte, 512)
		n, err := file.Read(buffer)
		if err != nil && n == 0 {
			http.Error(w, "Internal server error", http.StatusInternalServerError)
			return
		}
		contentType = http.DetectContentType(buffer[:n])

		// Seek back to the beginning of the file
		if _, err := file.Seek(0, 0); err != nil {
			http.Error(w, "Internal server error", http.StatusInternalServerError)
			return
		}
	}

	// Set response headers
	w.Header().Set("Content-Type", contentType)
	w.Header().Set("Content-Disposition", fmt.Sprintf("inline; filename=%q", filepath.Base(canonicalRequestedPath)))
	w.Header().Set("Content-Length", fmt.Sprintf("%d", fileInfo.Size()))
	w.Header().Set("X-Content-Type-Options", "nosniff")

	// Serve the file content using http.ServeContent for proper range support
	http.ServeContent(w, r, filepath.Base(canonicalRequestedPath), fileInfo.ModTime(), file)
}

func main() {
	// Ensure the uploads directory exists
	if err := os.MkdirAll(uploadsDir, 0755); err != nil {
		fmt.Fprintf(os.Stderr, "Failed to create uploads directory: %v\n", err)
		os.Exit(1)
	}

	http.HandleFunc("/file", fileHandler)

	fmt.Println("Server starting on :8080")
	fmt.Println("Usage: GET /file?filename=example.txt")

	if err := http.ListenAndServe(":8080", nil); err != nil {
		fmt.Fprintf(os.Stderr, "Server failed: %v\n", err)
		os.Exit(1)
	}
}